PROCEDURE Quantize(analogValue, bitDepth)
INPUT: Continuous analog value, desired bit depth
OUTPUT: Quantized digital value

BEGIN
 // Number of discrete levels
 levels ← 2^bitDepth

 // Range of input values
 minValue ← 0
 maxValue ← 255

 // Quantization step size
 stepSize ← (maxValue - minValue) / levels

 // Map analog to discrete level
 // Round to nearest level
 level ← Round(analogValue / stepSize)

 // Clamp to valid range
 IF level < 0 THEN level ← 0
 IF level >= levels THEN level ← levels - 1

 // Convert back to digital value
 digitalValue ← level × stepSize

 RETURN digitalValue
END

// Example: Quantize value 180 with 8-bit (256 levels)
// stepSize = 255/256 ≈ 0.996
// level = Round(180/0.996) = Round(180.7) = 181
// digitalValue = 181 × 0.996 ≈ 180.3
